import numpy as np
from scipy.linalg import expm
from typing import Dict, List

class QuantumCD:
    def __init__(self, n_visible: int, n_hidden: int, k_steps: int = 1):
        self.n_visible = n_visible
        self.n_hidden = n_hidden
        self.n_total = n_visible + n_hidden
        self.dim = 2 ** self.n_total
        self.k = k_steps

        self.I = np.eye(2, dtype=complex)
        self.X = np.array([[0, 1], [1, 0]], dtype=complex)
        self.Z = np.array([[1, 0], [0, -1]], dtype=complex)

    def _single_op(self, op: np.ndarray, qubit: int) -> np.ndarray:
        result = np.array([[1]], dtype=complex)
        for i in range(self.n_total):
            result = np.kron(result, op if i == qubit else self.I)
        return result

    def build_hamiltonian(self, params: Dict) -> np.ndarray:
        H = np.zeros((self.dim, self.dim), dtype=complex)

        for i in range(self.n_visible):
            H -= params['a'][i] * self._single_op(self.Z, i)

        for j in range(self.n_hidden):
            H -= params['b'][j] * self._single_op(self.Z, self.n_visible + j)

        for i in range(self.n_visible):
            for j in range(self.n_hidden):
                ZZ = self._single_op(self.Z, i) @ self._single_op(self.Z, self.n_visible + j)
                H -= params['W'][i, j] * ZZ

        for k in range(self.n_total):
            H -= params['gamma'] * self._single_op(self.X, k)

        return H

    def initialize_from_data(self, v: np.ndarray) -> np.ndarray:
        dim_v = 2 ** self.n_visible
        dim_h = 2 ** self.n_hidden

        v_idx = int(sum(v[i] * 2**i for i in range(self.n_visible)))
        psi_v = np.zeros(dim_v, dtype=complex)
        psi_v[v_idx] = 1.0

        psi_h = np.ones(dim_h, dtype=complex) / np.sqrt(dim_h)

        return np.kron(psi_v, psi_h)

    def evolve_state(self, psi: np.ndarray, H: np.ndarray, tau: float) -> np.ndarray:
        evolved = expm(-tau * H) @ psi
        return evolved / np.linalg.norm(evolved)

    def compute_expectations(self, psi: np.ndarray) -> Dict[str, np.ndarray]:
        rho = np.outer(psi, psi.conj())

        Z_v = np.zeros(self.n_visible)
        for i in range(self.n_visible):
            Z_v[i] = np.real(np.trace(self._single_op(self.Z, i) @ rho))

        Z_h = np.zeros(self.n_hidden)
        for j in range(self.n_hidden):
            Z_h[j] = np.real(np.trace(self._single_op(self.Z, self.n_visible + j) @ rho))

        ZZ = np.zeros((self.n_visible, self.n_hidden))
        for i in range(self.n_visible):
            for j in range(self.n_hidden):
                op = self._single_op(self.Z, i) @ self._single_op(self.Z, self.n_visible + j)
                ZZ[i, j] = np.real(np.trace(op @ rho))

        return {'Z_v': Z_v, 'Z_h': Z_h, 'ZZ': ZZ}

    def cd_gradient(self, params: Dict, data: np.ndarray, tau: float = 0.1) -> Dict[str, np.ndarray]:
        H = self.build_hamiltonian(params)
        n_samples = len(data)

        grad_a = np.zeros(self.n_visible)
        grad_b = np.zeros(self.n_hidden)
        grad_W = np.zeros((self.n_visible, self.n_hidden))
        grad_gamma = 0.0

        for v in data:
            psi_data = self.initialize_from_data(v)
            exp_data = self.compute_expectations(psi_data)

            psi_model = psi_data.copy()
            for _ in range(self.k):
                psi_model = self.evolve_state(psi_model, H, tau)
            exp_model = self.compute_expectations(psi_model)

            grad_a += (exp_model['Z_v'] - exp_data['Z_v']) / n_samples
            grad_b += (exp_model['Z_h'] - exp_data['Z_h']) / n_samples
            grad_W += (exp_model['ZZ'] - exp_data['ZZ']) / n_samples

        return {'a': grad_a, 'b': grad_b, 'W': grad_W, 'gamma': grad_gamma}

import numpy as np
from scipy.linalg import expm
from typing import Dict, List, Tuple

class QBMTrainer:
    def __init__(self, n_visible: int, n_hidden: int, learning_rate: float = 0.1, beta: float = 1.0):
        self.n_visible = n_visible
        self.n_hidden = n_hidden
        self.n_total = n_visible + n_hidden
        self.dim = 2 ** self.n_total
        self.lr = learning_rate
        self.beta = beta
        self.params = self._initialize_params()
        self.loss_history = []
        self.I = np.eye(2, dtype=complex)
        self.X = np.array([[0, 1], [1, 0]], dtype=complex)
        self.Z = np.array([[1, 0], [0, -1]], dtype=complex)

    def _initialize_params(self) -> Dict[str, np.ndarray]:
        return {
            'a': np.random.randn(self.n_visible) * 0.1,
            'b': np.random.randn(self.n_hidden) * 0.1,
            'W': np.random.randn(self.n_visible, self.n_hidden) * 0.1,
            'gamma': np.abs(np.random.randn()) * 0.1
        }

    def _single_op(self, op, q):
        result = np.array([[1]], dtype=complex)
        for i in range(self.n_total):
            result = np.kron(result, op if i == q else self.I)
        return result

    def build_hamiltonian(self) -> np.ndarray:
        H = np.zeros((self.dim, self.dim), dtype=complex)
        for i in range(self.n_visible):
            H -= self.params['a'][i] * self._single_op(self.Z, i)
        for j in range(self.n_hidden):
            H -= self.params['b'][j] * self._single_op(self.Z, self.n_visible + j)
        for i in range(self.n_visible):
            for j in range(self.n_hidden):
                H -= self.params['W'][i, j] * self._single_op(self.Z, i) @ self._single_op(self.Z, self.n_visible + j)
        for k in range(self.n_total):
            H -= self.params['gamma'] * self._single_op(self.X, k)
        return H

    def compute_gibbs_state(self, H: np.ndarray) -> np.ndarray:
        exp_H = expm(-self.beta * H)
        return exp_H / np.trace(exp_H)

    def visible_marginal(self, rho: np.ndarray) -> np.ndarray:
        dim_v = 2 ** self.n_visible
        dim_h = 2 ** self.n_hidden
        rho_reshaped = rho.reshape(dim_v, dim_h, dim_v, dim_h)
        rho_v = np.einsum('ijik->jk', rho_reshaped)
        return np.real(np.diag(rho_v))

    def compute_nll_loss(self, data: np.ndarray) -> float:
        H = self.build_hamiltonian()
        rho = self.compute_gibbs_state(H)
        probs = self.visible_marginal(rho)
        nll = 0.0
        for v in data:
            v_idx = int(sum(v[i] * 2**i for i in range(self.n_visible)))
            nll -= np.log(max(probs[v_idx], 1e-10))
        return nll / len(data)

    def compute_gradients(self, data: np.ndarray, method: str = 'exact') -> Dict[str, np.ndarray]:
        H = self.build_hamiltonian()
        rho = self.compute_gibbs_state(H)

        grad_a = np.zeros(self.n_visible)
        grad_b = np.zeros(self.n_hidden)
        grad_W = np.zeros((self.n_visible, self.n_hidden))

        # Model expectations (negative phase)
        for i in range(self.n_visible):
            grad_a[i] = -self.beta * np.real(np.trace(self._single_op(self.Z, i) @ rho))
        for j in range(self.n_hidden):
            grad_b[j] = -self.beta * np.real(np.trace(self._single_op(self.Z, self.n_visible + j) @ rho))
        for i in range(self.n_visible):
            for j in range(self.n_hidden):
                ZZ = self._single_op(self.Z, i) @ self._single_op(self.Z, self.n_visible + j)
                grad_W[i, j] = -self.beta * np.real(np.trace(ZZ @ rho))

        # Data expectations (positive phase)
        for v in data:
            v_idx = int(sum(v[i] * 2**i for i in range(self.n_visible)))
            for i in range(self.n_visible):
                z_val = 1 - 2 * v[i]
                grad_a[i] += self.beta * z_val / len(data)

        return {'a': grad_a, 'b': grad_b, 'W': grad_W}

    def update_params(self, grads: Dict[str, np.ndarray]):
        self.params['a'] -= self.lr * grads['a']
        self.params['b'] -= self.lr * grads['b']
        self.params['W'] -= self.lr * grads['W']

    def train(self, data: np.ndarray, n_epochs: int = 100, verbose: bool = True) -> List[float]:
        for epoch in range(n_epochs):
            grads = self.compute_gradients(data)
            self.update_params(grads)
            loss = self.compute_nll_loss(data)
            self.loss_history.append(loss)
            if verbose and epoch % 10 == 0:
                print(f"Epoch {epoch}: NLL = {loss:.4f}")
        return self.loss_history

    def sample(self, n_samples: int = 100) -> np.ndarray:
        H = self.build_hamiltonian()
        rho = self.compute_gibbs_state(H)
        probs = self.visible_marginal(rho)
        probs = probs / np.sum(probs)
        samples = np.random.choice(len(probs), size=n_samples, p=probs)
        return np.array([[(s >> i) & 1 for i in range(self.n_visible)] for s in samples])
